/* 伪代码：模块内部隐藏状态 */
static volatile uint32_t system_tick_count = 0;

/* 仅通过接口暴露读取能力，保护了状态的完整性 */
uint32_t Get_System_Ticks(void) {
    return system_tick_count;
}

typedef struct {
    UART_HandleTypeDef *huart;
    uint8_t buffer[64];
    uint16_t head;
} Serial_Device_t;

/* 驱动初始化：传入句柄，实现解耦 */
void Serial_Init(Serial_Device_t *dev, UART_HandleTypeDef *huart) {
    dev->huart = huart;
    dev->head = 0;
    /* 使能串口中断：配置优先级，确保不被抢占 */
    HAL_UART_Receive_IT(dev->huart, &dev->buffer[0], 1);
}

/* 必须使用 volatile */
static volatile uint8_t g_uart_rx_ready = 0;

void HAL_UART_RxCpltCallback(UART_HandleTypeDef *huart) {
    g_uart_rx_ready = 1; // 在中断中置位
}

